INSERT INTO public.cas_usage_mvp (id, code, "ancienCode", titre, description, "institutionSourceCode", "institutionCibleCode", "autresInstitutions", "donneesEchangees", "registresConcernes", "axePrioritaire", impact, complexite, "phaseMVPId", "statutImpl", prerequis, "conventionRequise", "conventionSignee", "dateIdentification", "dateLancement", "dateMiseEnProd", notes, timeline, observations, "statutVueSection", "resumeMetier", "baseLegale", "createdAt", "updatedAt", "sourceProposition", "sourceDetail", "niveauMaturite", "dateAdoption", "adopteParInstitutionId", "adopteParUserId", "fusionneVersId", typologie, "reclassementsTypologie", "conventionLieeId", "codeHistorique") VALUES ('9ffcd8c3-c505-4255-9b1b-a22d61fba96b', 'PINS-TECH-0008', NULL, 'Cycle complet douanier liquidation, recouvrement et bon a enlever', 'Trois services X-Road interconnectant GAINDE et SIGIF. (1) GAINDE→SIGIF: transmission temps réel des déclarations validées avec détail des droits par nature de taxe (40+ codes). (2) Paiement: validation dans SIGIF, comptabilisation par nature, quittance. (3) SIGIF→GAINDE: retour quittance pour émargement BAE.', 'DGD', 'DGCPT', NULL, 'Numéro déclaration (année-bureau-numéro), code PPM déclarant, détail taxes par code (Trésor, UEMOA, CEDEAO), référence avis validation, quittances, date envoi, code créditaire', NULL, 'Finances publiques — Doing Business', 'CRITIQUE', 'CRITIQUE', (SELECT id FROM phases_mvp WHERE code = 'MVP-2.0'), 'IDENTIFIE', NULL, true, false, NULL, NULL, NULL, NULL, NULL, 'PRIORITÉ 1. IMPACT DB MAXIMAL. Réduction cycle liquidation→BAE de 48h+ à temps réel. 3 services X-Road. Table correspondance bureau douane/percepteur. Mapping 40+ codes taxes → comptes SIGIF. GAINDE repensé + SIGIF imminent = fenêtre d''opportunité.', 'PROPOSE', NULL, NULL, '2026-04-22 22:49:19.96', '2026-04-22 22:49:19.96', 'ETUDE_SENUM', 'Cas d''usage issu du seed MVP 0, catalogue historique', 'ESQUISSE', NULL, NULL, NULL, NULL, 'TECHNIQUE', NULL, NULL, 'UC-GIZ-FIN-02') ON CONFLICT DO NOTHING;
